concept_sql:
SELECT card.type, card.count
FROM card
GROUP BY card.type;

compiled_sql:
SELECT card.type, COUNT(card.card_id)
FROM card
GROUP BY card.type;

concept_sql:
SELECT card.type, COUNT(card.card_id) as card_count
FROM card
GROUP BY card.type;

compiled_sql:
SELECT card.type, COUNT(card.card_id) as card_count
FROM card
GROUP BY card.type;

SELECT AVG(trans.balance)
FROM trans
JOIN account ON trans.account_id = account.account_id GROUP BY account.account_id;

